import ffmpeg

def solve(input_stream, output_format):
    if output_format not in ['HLS', 'DASH']:
        raise ValueError("Unsupported output format. Choose 'HLS' or 'DASH'.")

    output_stream = f'output.{output_format.lower()}'

    try:
        if input_stream.endswith('.flv'):
            # Transcode H.264 in FLV to HLS
            ffmpeg.input(input_stream).output(output_stream, format='hls').run()
        elif input_stream.endswith('.mjpeg'):
            # Transcode Motion-JPEG to HLS
            ffmpeg.input(input_stream).output(output_stream, format='hls').run()
        else:
            raise ValueError("Unsupported input stream format. Use '.flv' or '.mjpeg'.")
    except Exception as e:
        print(f"Error during transcoding: {e}")
        return None

    return output_stream
